%%%%%%%%%% Function fTrexSigInfV01.m %%%%%%%%%%% Function Figure Information, ver.1% Kei Nakamura% Created on Saturday, June 9th 2007.% Modified on %% function inf = fTrexSigInfV01(sig);% returns a information string for figure%function inf = fTrexSigInfV01(anl);  %function headerinf{1} = strcat('mean energy [MeV]:',num2str(ceil(anl.meanEnrgMev)));inf{2} = strcat('resolution [%,rms]:',num2str(0.1*ceil(10*anl.rsltnHPcnt)));inf{3} = strcat('energy spread [%,rms]:',num2str(0.1*ceil(10*anl.engSprdHPcnt)));inf{4} = strcat('divergence [mrad,rms]:',num2str(0.1*ceil(10*anl.beamDivMrad)));inf{5} = strcat('beam mean angle [mrad]:',num2str(ceil(anl.anglMrad)));
